# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
import mimetypes
from datetime import datetime
from flask import Flask, jsonify, request, send_file, abort

app = Flask(__name__)

USER_ROOTS = {
    "user1": os.path.abspath("./storage/user1"),
    "user2": os.path.abspath("./storage/user2"),
}

for root in USER_ROOTS.values():
    os.makedirs(root, exist_ok=True)


def get_user_root(user_id: str) -> str:
    root = USER_ROOTS.get(user_id)
    if not root:
        abort(404, description="User not found")
    return root


def resolve_user_path(user_id: str, relative_path: str) -> str:
    root = get_user_root(user_id)
    relative_path = relative_path or ""
    normalized = os.path.normpath(relative_path)
    full_path = os.path.normpath(os.path.join(root, normalized))
    if os.path.commonpath([root, full_path]) != root:
        abort(403, description="Path escapes user root")
    return full_path


def stat_to_info(path: str, root: str) -> dict:
    st = os.stat(path)
    rel_path = os.path.relpath(path, root)
    if rel_path == ".":
        rel_path = ""
    return {
        "name": os.path.basename(path) if rel_path else "",
        "path": rel_path.replace("\\", "/"),
        "is_dir": os.path.isdir(path),
        "size": st.st_size,
        "modified": datetime.fromtimestamp(st.st_mtime).isoformat(),
        "created": datetime.fromtimestamp(st.st_ctime).isoformat(),
    }


@app.get("/users/<user_id>/files")
def list_directory():
    user_id = request.view_args["user_id"]
    rel_path = request.args.get("path", "")
    full_path = resolve_user_path(user_id, rel_path)
    root = get_user_root(user_id)

    if not os.path.exists(full_path):
        abort(404, description="Path not found")
    if not os.path.isdir(full_path):
        abort(400, description="Path is not a directory")

    items = []
    for name in sorted(os.listdir(full_path)):
        item_path = os.path.join(full_path, name)
        info = stat_to_info(item_path, root)
        items.append(info)

    current = os.path.relpath(full_path, root)
    if current == ".":
        current = ""

    return jsonify({
        "path": current.replace("\\", "/"),
        "items": items,
    })


@app.get("/users/<user_id>/files/info")
def get_file_info():
    user_id = request.view_args["user_id"]
    rel_path = request.args.get("path", "")
    full_path = resolve_user_path(user_id, rel_path)
    root = get_user_root(user_id)

    if not os.path.exists(full_path):
        abort(404, description="Path not found")

    info = stat_to_info(full_path, root)
    if os.path.isfile(full_path):
        mime_type, _ = mimetypes.guess_type(full_path)
        info["mime_type"] = mime_type or "application/octet-stream"

    return jsonify(info)


@app.get("/users/<user_id>/files/download")
def download_file():
    user_id = request.view_args["user_id"]
    rel_path = request.args.get("path", "")
    full_path = resolve_user_path(user_id, rel_path)

    if not os.path.exists(full_path):
        abort(404, description="Path not found")
    if not os.path.isfile(full_path):
        abort(400, description="Path is not a file")

    return send_file(full_path, as_attachment=True, download_name=os.path.basename(full_path))


@app.errorhandler(400)
@app.errorhandler(403)
@app.errorhandler(404)
def handle_error(err):
    return jsonify({"error": err.description}), err.code


if __name__ == "__main__":
    app.run(debug=True)